/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Cotação de Frete"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &CotCod.IsEmpty() print printBlockFilterCotCod EndIf If not &CotPedCod.IsEmpty() print printBlockFilterCotPedCod EndIf If not &CotDta.IsEmpty() print printBlockFilterCotDta EndIf If not &CotDta_To.IsEmpty() &CotDta_To_Description = format('%1 (%2)', "Data", "à") print printBlockFilterCotDta_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'COTTRACODRAZ' &CotTraCodRaz1.FromString(&GridStateDynamicFilter.Value) If not &CotTraCodRaz1.IsEmpty() &CotTraCodRaz = &CotTraCodRaz1 print printBlockFilterCotTraCodRaz EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'COTTRACODRAZ' &CotTraCodRaz2.FromString(&GridStateDynamicFilter.Value) If not &CotTraCodRaz2.IsEmpty() &CotTraCodRaz = &CotTraCodRaz2 print printBlockFilterCotTraCodRaz EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'COTTRACODRAZ' &CotTraCodRaz3.FromString(&GridStateDynamicFilter.Value) If not &CotTraCodRaz3.IsEmpty() &CotTraCodRaz = &CotTraCodRaz3 print printBlockFilterCotTraCodRaz EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod (CotCod) when &OrderedBy = 1 order CotCod when &OrderedBy = 2 AND &OrderedDsc = False order (CotCod) when &OrderedBy = 2 AND &OrderedDsc = True order CotPedCod when &OrderedBy = 3 AND &OrderedDsc = False order (CotPedCod) when &OrderedBy = 3 AND &OrderedDsc = True order CotNro when &OrderedBy = 4 AND &OrderedDsc = False order (CotNro) when &OrderedBy = 4 AND &OrderedDsc = True order CotVlr when &OrderedBy = 5 AND &OrderedDsc = False order (CotVlr) when &OrderedBy = 5 AND &OrderedDsc = True order CotIs when &OrderedBy = 6 AND &OrderedDsc = False order (CotIs) when &OrderedBy = 6 AND &OrderedDsc = True
using DSWWCotacaoFrete(&CotCod, &CotPedCod, &DynamicFiltersSelector1, &CotTraCodRaz1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &CotTraCodRaz2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &CotTraCodRaz3, &CotDta, &CotDta_To) &DataHora = trim(DtoC(CotDta)) + ' ' + trim(CotHor) &gridCotTraCodRaz = CotTraCodRaz RetornaTotalLiquidoBruto.Call(EmpCod, CotFilCod, CotPedCod, &PedVlrBrt, &PedVlrLiq)
&Percentual = 0 if &PedVlrLiq > 0 and CotVlr > 0 &Percentual = (CotVlr / &PedVlrLiq) * 100 if &Percentual < 0 &Percentual = 0 EndIF EndIF
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWCotacaoFreteGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWCotacaoFreteGridState")) Else &GridState.FromXml(&Session.Get(!"WWCotacaoFreteGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"COTCOD" &CotCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"COTPEDCOD" &CotPedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"COTDTA" &CotDta.FromString(&GridStateFilterValue.Value) &CotDta_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

Output_file("ExportReportWWCotacaoFrete","PDF");

